const items = $input.all();

function pad(n){ return String(n).padStart(2,'0'); }

function parseBR_SP_toMs(s){
  if(!s || typeof s !== 'string' || !s.includes(' - ')) return null;
  const [datePart, timePart] = s.split(' - ');
  const [dd, mm, yyyy] = datePart.split('/').map(Number);
  const [HH, min] = timePart.split(':').map(Number);
  const iso = `${yyyy}-${pad(mm)}-${pad(dd)}T${pad(HH)}:${pad(min)}:00-03:00`;
  const t = Date.parse(iso);
  return Number.isNaN(t) ? null : t;
}

function nowInSaoPauloMs(){
  const now = new Date();
  const parts = Object.fromEntries(
    new Intl.DateTimeFormat('en-CA', {
      timeZone: 'America/Sao_Paulo',
      year: 'numeric', month: '2-digit', day: '2-digit',
      hour: '2-digit', minute: '2-digit', second: '2-digit',
      hour12: false
    }).formatToParts(now).map(p => [p.type, p.value])
  );
  const isoSP = `${parts.year}-${parts.month}-${parts.day}T${parts.hour}:${parts.minute}:${parts.second}-03:00`;
  return Date.parse(isoSP);
}

function formatNowSP(ms){
  const d = new Date(ms);
  const data = new Intl.DateTimeFormat('pt-BR', { timeZone: 'America/Sao_Paulo', day: '2-digit', month: '2-digit', year: 'numeric' }).format(d);
  const hora = new Intl.DateTimeFormat('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit', hour12: false }).format(d);
  return `${data} - ${hora}`;
}

function extractDiaBR(s){
  if (typeof s !== 'string') return null;
  const idx = s.indexOf(' - ');
  if (idx === -1) return null;
  const datePart = s.slice(0, idx).trim();
  return /^\d{2}\/\d{2}\/\d{4}$/.test(datePart) ? datePart : null;
}

const followMap = new Map([
  [120,  'follow 2h'],
  [1440, 'follow 24h'],
  [2880, 'follow 48h'],
  [4320, 'follow 72h'],
  [5760, 'follow 96h'],
  [7200, 'follow 120h'],
]);

const nowSpMs = nowInSaoPauloMs();
const now_formatted = formatNowSP(nowSpMs);

const byNomeDia = new Map();
for (const it of items) {
  const r = it.json || it;
  const nome = (r.nome || '').trim();
  const dia = extractDiaBR(r.hora_dia_exato);
  if (!nome || !dia) continue;

  const key = `${nome.toLowerCase()}#${dia}`;
  const cur = byNomeDia.get(key);
  if (!cur || new Date(r.createdAt) > new Date(cur.createdAt)) {
    byNomeDia.set(key, r);
  }
}
const deduped = Array.from(byNomeDia.values());

return deduped.map(input => {
  const s = input.hora_dia_exato;
  const tInput = parseBR_SP_toMs(s);

  let followup = '';
  let diffMin = null;

  if (tInput != null) {
    diffMin = Math.floor((nowSpMs - tInput) / 60000);

    if (diffMin > 7200) {
      followup = 'acabou followUp';
    } else if (diffMin >= 0) {
      followup = followMap.get(diffMin) || '';
    }
  }

  const diffHoursInt = (diffMin == null) ? null : Math.floor(diffMin / 60);
  const diffHoursTotal = (diffMin == null) ? null : Number((diffMin / 60).toFixed(2));

  return {
    json: {
      whatsapp: input.whatsapp,
      ticketId: input.ticketId,
      nome: input.nome,
      hora_dia_exato_input: s || 'Inválido',
      now_formatted,
      diferenca_minutos_total: diffMin,
      diferenca_horas_inteiras: diffHoursInt,
      diferenca_horas_total: diffHoursTotal,
      followup
    }
  };
});

// Array contendo as frases que queremos verificar
const frases = [
  "Estou passando por aperto financeiro e vi seu material. Pode explicar?",
  "Preciso de um empréstimo urgente e vi seu material. Pode explicar?",
  "Tenho dificuldade em lidar com pessoas e vi seu material. Pode explicar?",
  "Tenho dificuldade de foco e produtividade e vi seu material. Pode explicar?",
  "Sinto dores por usar muito o celular e vi seu material. Pode explicar?",
  "Vi o guia de cuidados para pets em recuperação e quero saber mais.",
  "Tenho sofrido com ansiedade leve e vi seu material. Pode explicar?",
  "Tenho dificuldade para dormir e vi seu material. Pode explicar?",
  "Tenho dificuldade para organizar minha casa e vi seu material. Pode explicar?",
  "Tenho dificuldade para manter uma alimentação saudável e vi seu material. Pode explicar?"
];

// Supondo que 'items' é o array de entrada no n8n. 
// Para Make ou JavaScript comum, apenas substitua 'items' pelo seu array de objetos (ex: payload).
// Este código mapeia cada item do array de entrada.
return items.map(item => {
  // Ajuste o caminho da propriedade 'body' conforme a estrutura do seu JSON. 
  // No n8n normalmente é item.json.body. Se for um array simples, use apenas item.body
  const body = item.json ? item.json.body : item.body;

  // Verifica se o 'body' está na lista de frases
  const correspondencia = frases.includes(body);

  // Retorna o objeto original com a nova propriedade 'resultado_frase'
  return {
    ...(item.json || item), // Mantém todas as propriedades originais
    resultado_frase: correspondencia ? "sim" : "não"
  };
});

