// n8n Function node
// Entrada: múltiplos itens (linhas da tabela Messages)
// Saída: quem enviou por último: "voce" (fromMe=true) ou "cliente" (fromMe=false)

function toMs(m){
  // Prioriza createdAt; se faltar, usa timestamp (ms em string/number)
  if (m.createdAt) {
    const t = Date.parse(m.createdAt);
    if (!Number.isNaN(t)) return t;
  }
  if (m.timestamp != null) {
    const n = Number(m.timestamp);
    if (!Number.isNaN(n)) return n;
  }
  return -Infinity; // ignora se não tiver data válida
}

// Achar o item mais recente entre os itens de entrada
let latest = null;
let latestMs = -Infinity;

for (const it of items) {
  const m = it.json || {};
  const t = toMs(m);
  if (t > latestMs) {
    latestMs = t;
    latest = m;
  }
}

if (!latest || latestMs === -Infinity) {
  return [{ json: { error: 'Sem mensagens com createdAt/timestamp válidos' } }];
}

const quem = latest.fromMe ? 'voce' : 'cliente';

return [{
  json: {
    quem_enviou_por_ultimo: quem,
    fromMe: !!latest.fromMe,
    messageId: latest.id ?? latest.messageId ?? null,
    body: latest.body ?? null,
    createdAt: latest.createdAt ?? null,
    timestamp: latest.timestamp ?? null,
    ticketId: latest.ticketId ?? null,
    contactId: latest.contactId ?? null
  }
}];

