function toMs(m){
  // Prioriza createdAt; se faltar, usa timestamp (ms em string/number)
  if (m.createdAt) {
    const t = Date.parse(m.createdAt);
    if (!Number.isNaN(t)) return t;
  }
  if (m.timestamp != null) {
    const n = Number(m.timestamp);
    if (!Number.isNaN(n)) return n;
  }
  return -Infinity; // ignora se não tiver data válida
}

